-- seed-translations.sql — UK/EN переклади турів і спецмаршрутів.
-- Згенеровано автоматично. Merge у translations jsonb (|| зберігає наявні ключі).
-- Запусти у Supabase SQL Editor.

BEGIN;

UPDATE tours SET translations = COALESCE(translations,'{}'::jsonb) || '{"uk": {"title": "Індивідуальна екскурсія з Токіо до гори Фудзі", "summary": "Найкрасивіші види священної гори, традиційна Японія та легендарні фотолокації за один день.", "description": "Кітагуті Хонгу Фудзі Сенген Тайся — найважливіше святилище, легенди про Фудзі, синтоїстські традиції.\r\n\r\nОсіно Хаккай — село з 8 кришталевими джерелами, водяні млини.\r\n\r\nПагода Тюрейто — одна з найвідоміших пам''яток, панорамний вид.\r\n\r\nМузей Іттіку Куботи — давня техніка фарбування шовку «цудзігахана».\r\n\r\nПарк Оісі — оглядовий майданчик на березі озера Кавагутіко.\r\n\r\nДодаткові локації: водоспад Сірайто (ЮНЕСКО), чайні плантації, Льодова печера Нарусава та Печера вітрів Фугаку, ліс Аокігахара.", "org_details": "Початок можливий з Токіо, Хаконе або Одавари.\r\nТривалість 9–10 годин.\r\nМаршрут коригується залежно від погоди, видимості Фудзі та побажань гостей.", "price_details": "$1200 за групу до 7 осіб незалежно від кількості учасників\r\nДля груп 8–12 осіб — організація на мікроавтобусі, ціна обговорюється.", "participants": "до 7 осіб", "includes": ["Послуги гіда", "Транспортне обслуговування"], "stops": [{"title": "Кітагуті Хонгу Фудзі Сенген Тайся", "text": "Найважливіше святилище біля підніжжя Фудзі: легенди про гору та синтоїстські традиції."}, {"title": "Осіно Хаккай", "text": "Село з вісьмома кришталевими джерелами та водяними млинами."}, {"title": "Пагода Тюрейто", "text": "Одна з найвідоміших панорам Японії: пагода та Фудзі на тлі сакури."}, {"title": "Музей Іттіку Куботи", "text": "Давня техніка фарбування шовку «цудзігахана»."}, {"title": "Парк Оісі", "text": "Оглядовий майданчик на березі озера Кавагутіко з видом на Фудзі."}]}, "en": {"title": "Private Day Tour from Tokyo to Mt. Fuji", "summary": "The most beautiful views of the sacred mountain, traditional Japan and legendary photo spots in a single day.", "description": "Kitaguchi Hongu Fuji Sengen Taisha — the most important shrine, legends of Mt. Fuji, Shinto traditions.\r\n\r\nOshino Hakkai — a village with 8 crystal-clear springs and water mills.\r\n\r\nChureito Pagoda — one of the most famous landmarks, with a panoramic view.\r\n\r\nItchiku Kubota Museum — the ancient \"tsujigahana\" silk-dyeing technique.\r\n\r\nOishi Park — a viewpoint on the shore of Lake Kawaguchiko.\r\n\r\nAdditional locations: Shiraito Falls (UNESCO), tea plantations, the Narusawa Ice Cave and the Fugaku Wind Cave, Aokigahara Forest.", "org_details": "The tour can start from Tokyo, Hakone or Odawara.\r\nDuration 9–10 hours.\r\nThe route is adjusted depending on the weather, the visibility of Mt. Fuji and the guests'' wishes.", "price_details": "$1200 per group of up to 7 people regardless of the number of participants\r\nFor groups of 8–12 people — arrangement by minibus, price negotiable.", "participants": "up to 7 people", "includes": ["Guide services", "Transportation service"], "stops": [{"title": "Kitaguchi Hongu Fuji Sengen Taisha", "text": "The most important shrine at the foot of Mt. Fuji: legends of the mountain and Shinto traditions."}, {"title": "Oshino Hakkai", "text": "A village with eight crystal-clear springs and water mills."}, {"title": "Chureito Pagoda", "text": "One of Japan''s most famous panoramas: the pagoda and Mt. Fuji against a backdrop of cherry blossoms."}, {"title": "Itchiku Kubota Museum", "text": "The ancient \"tsujigahana\" silk-dyeing technique."}, {"title": "Oishi Park", "text": "A viewpoint on the shore of Lake Kawaguchiko with a view of Mt. Fuji."}]}}'::jsonb WHERE slug = 'fudzi';
UPDATE tours SET translations = COALESCE(translations,'{}'::jsonb) || '{"uk": {"title": "Індивідуальна оглядова екскурсія по Хаконе", "summary": "Подорож серед вулканів, гірських озер, старовинних доріг та самурайської історії.", "description": "Канатна дорога Хаконе — вулканічні ландшафти, вид на Фудзі та озеро Асі.\r\n\r\nВулканічна долина Овакудані — фумароли, сірчані джерела, чорні яйця.\r\n\r\nПрогулянка озером Асі — стилізований корабель, кратерне озеро.\r\n\r\nСвятилище Хаконе — VIII століття, серед криптомерій.\r\n\r\nЧервоні торії на воді.\r\n\r\nСтаровинна дорога Токайдо — 400+ років, кам''яна дорога, криптомерії.\r\n\r\nСамурайська застава Хаконе — реконструкція епохи Едо.\r\n\r\nДодаткові локації: Музей просто неба Хаконе (Генрі Мур, Пікассо), Імператорський парк Онсі Хаконе, Музей Пола.", "org_details": "Початок з Токіо, Одавари або Хаконе.\r\nКожна екскурсія адаптується під інтереси гостей.", "price_details": "Виїзд із Токіо: $1350 за групу до 7 осіб.\r\nДля груп 8–20 осіб: $90/особа + проїзний по Хаконе (~$45, сплачується окремо). Зустріч на ст. Hakone-Yumoto або Odawara.", "participants": "до 7 осіб", "includes": ["Послуги гіда", "Транспорт", "Квиток на канатну дорогу", "Прогулянка на кораблі озером Асі"], "excludes": ["Обід", "Особисті витрати", "Вхідні квитки до музеїв (за бажанням)", "Проїзний по Хаконе для груп 8–20 осіб (~€40)"], "stops": [{"title": "Канатна дорога Хаконе", "text": "Вулканічні ландшафти, вид на Фудзі та озеро Асі з висоти."}, {"title": "Долина Овакудані", "text": "Фумароли, сірчані джерела та знамениті чорні яйця."}, {"title": "Озеро Асі", "text": "Прогулянка на стилізованому кораблі кратерним озером."}, {"title": "Святилище Хаконе", "text": "Святилище VIII століття серед вікових криптомерій."}, {"title": "Червоні торії на воді", "text": "Знамениті ворота торії, що стоять просто в озері."}, {"title": "Старовинна дорога Токайдо", "text": "Кам''яна дорога, старша за 400 років, в алеї криптомерій."}, {"title": "Самурайська застава Хаконе", "text": "Реконструкція прикордонної застави епохи Едо."}]}, "en": {"title": "Private Sightseeing Tour of Hakone", "summary": "A journey among volcanoes, mountain lakes, ancient roads and samurai history.", "description": "Hakone Ropeway — volcanic landscapes, views of Mt. Fuji and Lake Ashi.\r\n\r\nThe volcanic valley of Owakudani — fumaroles, sulfur springs, black eggs.\r\n\r\nA cruise on Lake Ashi — a themed ship, a crater lake.\r\n\r\nHakone Shrine — 8th century, set among cryptomeria trees.\r\n\r\nThe red torii on the water.\r\n\r\nThe ancient Tokaido road — over 400 years old, a stone road lined with cryptomeria.\r\n\r\nHakone Samurai Checkpoint — a reconstruction of the Edo period.\r\n\r\nAdditional locations: the Hakone Open-Air Museum (Henry Moore, Picasso), the Onshi Hakone Imperial Park, the Pola Museum.", "org_details": "Starting from Tokyo, Odawara or Hakone.\r\nEach tour is tailored to the guests'' interests.", "price_details": "Departure from Tokyo: $1350 per group of up to 7 people.\r\nFor groups of 8–20 people: $90/person + a Hakone travel pass (~$45, paid separately). Meeting at Hakone-Yumoto or Odawara station.", "participants": "up to 7 people", "includes": ["Guide services", "Transportation", "Ropeway ticket", "Boat cruise on Lake Ashi"], "excludes": ["Lunch", "Personal expenses", "Museum admission tickets (optional)", "Hakone travel pass for groups of 8–20 people (~€40)"], "stops": [{"title": "Hakone Ropeway", "text": "Volcanic landscapes and views of Mt. Fuji and Lake Ashi from above."}, {"title": "Owakudani Valley", "text": "Fumaroles, sulfur springs and the famous black eggs."}, {"title": "Lake Ashi", "text": "A cruise on a themed ship across the crater lake."}, {"title": "Hakone Shrine", "text": "An 8th-century shrine among centuries-old cryptomeria trees."}, {"title": "The red torii on the water", "text": "The famous torii gate standing right in the lake."}, {"title": "The ancient Tokaido road", "text": "A stone road over 400 years old in an avenue of cryptomeria."}, {"title": "Hakone Samurai Checkpoint", "text": "A reconstruction of an Edo-period border checkpoint."}]}}'::jsonb WHERE slug = 'hakone';
UPDATE tours SET translations = COALESCE(translations,'{}'::jsonb) || '{"uk": {"title": "Старий тракт Токайдо: дорогою самураїв та мандрівників", "summary": "Індивідуальна екскурсія для гостей круїзних лайнерів: старовинні поштові станції, тунель Мейдзі Уцуноя, містечка Уцуноя-дзюку та Маріко-дзюку, парк і руїни замку Сумпу.", "description": "Цей маршрут відкриє перед вами іншу Японію — не сучасну, а ту, якою її бачили самураї, купці та паломники, що століттями подорожували знаменитим трактом Токайдо між Кіото та Едо. Ми вирушимо вглиб гірських долин Сідзуоки, де й сьогодні збереглася атмосфера старої Японії.\r\n\r\nПершою зупинкою стане Кашибая — історичний заїжджий двір, що приймав мандрівників на тракті Токайдо. Тут можна побачити, як виглядали традиційні заїжджі будинки епохи Едо, та дізнатися, як проходили подорожі Японією кілька століть тому.\r\n\r\nДалі ми відвідаємо тунель Мейдзі Уцуноя — унікальну інженерну споруду кінця XIX століття, збудовану в період стрімкої модернізації країни. Старовинна цегляна кладка й сьогодні нагадує про час, коли Японія відкривалася світу.\r\n\r\nПоряд розташоване Уцуноя-дзюку — мальовниче поштове містечко, де збереглися традиційні дерев''яні будинки, вузенькі вулички та атмосфера старого Токайдо.\r\n\r\nНаступною зупинкою стане Маріко-дзюку — одна з найвідоміших поштових станцій історичного тракту. Саме тут мандрівники відпочивали, куштували місцеві страви та готувалися до подальшої дороги через гори.\r\n\r\nНаприкінці ми повернемося до центру Сідзуоки, щоб відвідати парк Сумпу та руїни замку Сумпу — резиденції Токугави Іеясу, де великий сьоґун провів останні роки свого життя після об''єднання Японії.\r\n\r\nЦе маршрут для тих, хто любить історію, старовинні міста, атмосферні вулички та справжню Японію без натовпів туристів.", "org_details": "Основні локації: Кашибая · тунель Мейдзі Уцуноя · Уцуноя-дзюку · Маріко-дзюку · парк Сумпу · руїни замку Сумпу.", "participants": "Індивідуально (для гостей круїзу)", "includes": ["Зустріч і повернення в порт Сімідзу", "Комфортний автомобіль", "Послуги ліцензованого гіда", "Індивідуальний маршрут без великих туристичних груп"], "stops": [{"title": "Кашибая", "text": "Історичний заїжджий двір на тракті Токайдо епохи Едо."}, {"title": "Тунель Мейдзі Уцуноя", "text": "Цегляний тунель кінця XIX століття — пам''ятка модернізації Японії."}, {"title": "Уцуноя-дзюку", "text": "Мальовниче поштове містечко з традиційними дерев''яними будинками."}, {"title": "Маріко-дзюку", "text": "Одна з найвідоміших поштових станцій тракту Токайдо."}, {"title": "Парк і руїни замку Сумпу", "text": "Резиденція Токугави Іеясу, де сьоґун провів останні роки життя."}]}, "en": {"title": "The Old Tokaido Road: Along the Path of Samurai and Travelers", "summary": "A private tour for cruise-ship guests: ancient post stations, the Meiji Utsunoya Tunnel, the towns of Utsunoya-juku and Mariko-juku, and the park and ruins of Sumpu Castle.", "description": "This route will reveal a different Japan to you — not the modern one, but the one seen by the samurai, merchants and pilgrims who for centuries traveled the famous Tokaido road between Kyoto and Edo. We will venture deep into the mountain valleys of Shizuoka, where the atmosphere of old Japan survives to this day.\r\n\r\nOur first stop will be Kashibaya — a historic inn that hosted travelers on the Tokaido road. Here you can see what traditional Edo-period lodging houses looked like and learn how people journeyed across Japan several centuries ago.\r\n\r\nNext we will visit the Meiji Utsunoya Tunnel — a unique engineering structure from the late 19th century, built during the country''s rapid modernization. Its old brickwork still recalls the time when Japan was opening up to the world.\r\n\r\nNearby lies Utsunoya-juku — a picturesque post town that has preserved traditional wooden houses, narrow lanes and the atmosphere of the old Tokaido.\r\n\r\nThe next stop will be Mariko-juku — one of the most famous post stations on the historic road. It was here that travelers rested, sampled local dishes and prepared for the journey ahead through the mountains.\r\n\r\nFinally, we will return to the center of Shizuoka to visit Sumpu Park and the ruins of Sumpu Castle — the residence of Tokugawa Ieyasu, where the great shogun spent the final years of his life after unifying Japan.\r\n\r\nThis is a route for those who love history, ancient towns, atmospheric lanes and the real Japan without crowds of tourists.", "org_details": "Main locations: Kashibaya · Meiji Utsunoya Tunnel · Utsunoya-juku · Mariko-juku · Sumpu Park · ruins of Sumpu Castle.", "participants": "Private (for cruise guests)", "includes": ["Pickup and return at the port of Shimizu", "Comfortable car", "Licensed guide services", "A private route without large tourist groups"], "stops": [{"title": "Kashibaya", "text": "A historic inn on the Tokaido road from the Edo period."}, {"title": "Meiji Utsunoya Tunnel", "text": "A brick tunnel from the late 19th century — a monument to Japan''s modernization."}, {"title": "Utsunoya-juku", "text": "A picturesque post town with traditional wooden houses."}, {"title": "Mariko-juku", "text": "One of the most famous post stations on the Tokaido road."}, {"title": "Sumpu Park and Castle Ruins", "text": "The residence of Tokugawa Ieyasu, where the shogun spent the final years of his life."}]}}'::jsonb WHERE slug = 'tokaido-staryy-trakt';
UPDATE tours SET translations = COALESCE(translations,'{}'::jsonb) || '{"uk": {"title": "Нагано Premium — Японські Альпи, давні храми та Кусацу Онсен", "summary": "Індивідуальна подорож 4 дні / 3 ночі з Токіо: храм Дзенкодзі, снігові мавпи, Обусе та Хокусай, замок Мацумото й відпочинок у Кусацу Онсен.", "description": "Цей маршрут створено для тих, хто хоче побачити зовсім іншу Японію — величні гори, давні храми, самурайські замки, мистецтво епохи Едо та знамениті гарячі джерела.\r\n\r\nНа вас чекають неквапливі прогулянки історичними містечками, зустрічі з природою Японських Альп та відпочинок на одному з найкращих онсен-курортів країни.", "org_details": "4 дні / 3 ночі. Індивідуальний формат, комфортний автомобіль, супровід ліцензованого російськомовного гіда.\r\nПроживання, харчування та вхідні квитки — уточнюються при бронюванні.", "participants": "Індивідуально", "includes": ["Комфортний автомобіль", "Послуги ліцензованого російськомовного гіда", "Індивідуальний маршрут", "Гнучка програма під ваші побажання"], "excludes": ["Проживання", "Харчування та напої", "Особисті витрати"], "stops": [{"title": "День 1 · Дзенкодзі", "text": "Один із найдавніших буддійських храмів Японії, заснований майже 1400 років тому. Під головною залою — знаменитий темний коридор, символ шляху до просвітлення. Прогулянка старовинною торговою вулицею Накамісе."}, {"title": "День 2 · Парк снігових мавп Дзігокудані", "text": "Прогулянка лісовою стежкою до знаменитих японських макак, які цілий рік відпочивають у природних гарячих джерелах."}, {"title": "День 2 · Обусе та спадщина Хокусая", "text": "Містечко, що зберегло атмосферу епохи Едо: каштанові солодощі, музей Кацусіки Хокусая та грандіозний стельовий розпис «Фенікс» у храмі Гансьоїн."}, {"title": "День 3 · Святилище Тогакусі", "text": "Одне з найзагадковіших святилищ Японії, пов''язане з міфом про богиню сонця Аматерасу. Алея багатовікових кедрів — одна з найкрасивіших у країні."}, {"title": "День 3 · Обід на місо-броварні Ishii Miso", "text": "Сімейна броварня 1868 року: трирічне місо в кедрових діжках та фірмовий обід зі стравами кухні Сінсю."}, {"title": "День 3 · Замок Мацумото", "text": "«Замок Чорного Ворона» — один із дванадцяти оригінальних замків Японії та національний скарб країни."}, {"title": "День 3–4 · Кусацу Онсен", "text": "Один із трьох найвідоміших онсен-курортів Японії з тисячолітньою історією. Заселення в традиційний рьокан, вечеря кайсекі, термальні джерела."}, {"title": "День 4 · Юбатаке та шоу Юмомі", "text": "Головний символ Кусацу — дерев''яний комплекс Юбатаке; традиційне шоу охолодження гарячої води великими дерев''яними лопатками під народні пісні."}]}, "en": {"title": "Nagano Premium — the Japanese Alps, Ancient Temples and Kusatsu Onsen", "summary": "A private 4-day / 3-night journey from Tokyo: Zenkoji Temple, snow monkeys, Obuse and Hokusai, Matsumoto Castle and relaxation at Kusatsu Onsen.", "description": "This route is created for those who want to see a completely different Japan — majestic mountains, ancient temples, samurai castles, Edo-period art and famous hot springs.\r\n\r\nAwaiting you are leisurely strolls through historic towns, encounters with the nature of the Japanese Alps and relaxation at one of the country''s finest onsen resorts.", "org_details": "4 days / 3 nights. Private format, comfortable car, accompanied by a licensed Russian-speaking guide.\r\nAccommodation, meals and admission tickets — to be confirmed at booking.", "participants": "Private", "includes": ["Comfortable car", "Licensed Russian-speaking guide services", "Private route", "Flexible program tailored to your wishes"], "excludes": ["Accommodation", "Meals and drinks", "Personal expenses"], "stops": [{"title": "Day 1 · Zenkoji", "text": "One of Japan''s oldest Buddhist temples, founded almost 1,400 years ago. Beneath the main hall lies the famous dark corridor, a symbol of the path to enlightenment. A walk along the historic Nakamise shopping street."}, {"title": "Day 2 · Jigokudani Snow Monkey Park", "text": "A walk along a forest trail to the famous Japanese macaques, which relax in natural hot springs all year round."}, {"title": "Day 2 · Obuse and the Legacy of Hokusai", "text": "A town that has preserved the atmosphere of the Edo period: chestnut sweets, the Katsushika Hokusai museum and the grand ceiling painting \"Phoenix\" in Ganshoin Temple."}, {"title": "Day 3 · Togakushi Shrine", "text": "One of Japan''s most mysterious shrines, linked to the myth of the sun goddess Amaterasu. An avenue of centuries-old cedars — one of the most beautiful in the country."}, {"title": "Day 3 · Lunch at the Ishii Miso brewery", "text": "A family brewery founded in 1868: three-year-aged miso in cedar barrels and a signature lunch featuring dishes of Shinshu cuisine."}, {"title": "Day 3 · Matsumoto Castle", "text": "The \"Crow Castle\" — one of Japan''s twelve original castles and a national treasure of the country."}, {"title": "Day 3–4 · Kusatsu Onsen", "text": "One of Japan''s three most famous onsen resorts, with a thousand-year history. Check-in at a traditional ryokan, a kaiseki dinner, thermal springs."}, {"title": "Day 4 · Yubatake and the Yumomi Show", "text": "The main symbol of Kusatsu — the wooden Yubatake complex; a traditional show of cooling the hot water with large wooden paddles to the sound of folk songs."}]}}'::jsonb WHERE slug = 'nagano-premium';
UPDATE tours SET translations = COALESCE(translations,'{}'::jsonb) || '{"uk": {"title": "Одавара — місто непереможних самураїв", "summary": "Історія могутнього клану Ходзьо, старовинний замок, храми, ремесла та гастрономічні традиції на узбережжі Тихого океану.", "description": "Одавара — одне з найважливіших історичних міст префектури Канаґава, відоме самурайською спадщиною, замком клану Ходзьо та особливою атмосферою старої Японії. Основна програма розрахована на 6 годин і поєднує історію, культуру, ремесла та місцеву гастрономію.\r\n\r\nMinaka Odawara — сучасний комплекс у стилі замкового містечка з панорамною терасою.\r\n\r\nЗамок Одавара — головна пам''ятка, історія клану Ходзьо та оборона від Тойотомі Хідейосі.\r\n\r\nМузей самурайських обладунків — колекція справжніх обладунків та зброї.\r\n\r\nСвятилище Хотоку Ніномія-дзіндзя — присвячене Ніномії Сонтоку, знаменитому просвітителю.\r\n\r\nСтаровинні вулички — атмосфера епохи Едо, ремісничі крамнички.\r\n\r\nГастрономічна Одавара — камабоко (рибні тістечка), місцеві делікатеси.\r\n\r\nДодаткові локації: Храм Тенґу (Дайюдзан Сайдзьодзі), Музей камабоко Suzuhiro, Резиденція Мацунаґа та чайна церемонія, Порт Одавара, Enoura Observatory.", "org_details": "Можливий виїзд із Токіо та повернення після завершення програми.\r\nДодаткові локації обговорюються окремо.", "price_details": "Індивідуальна з трансфером із Токіо: $160/особа (група до 12 осіб), включено вхідні квитки до Замку та Музею обладунків\r\nПішохідна із зустріччю на ст. Одавара: $140/особа", "participants": "до 12 осіб", "includes": ["Послуги гіда", "Вхідні квитки до Замку Одавара", "Вхідні квитки до Музею самурайських обладунків"], "excludes": ["Додаткові музеї та опціональні локації"], "stops": [{"title": "Minaka Odawara", "text": "Сучасний комплекс у стилі замкового містечка з панорамною терасою та краєвидом на місто."}, {"title": "Замок Одавара", "text": "Головна пам''ятка: історія клану Ходзьо та оборона від Тойотомі Хідейосі."}, {"title": "Музей самурайських обладунків", "text": "Колекція справжніх самурайських обладунків та зброї."}, {"title": "Святилище Хотоку Ніномія", "text": "Присвячене Ніномії Сонтоку — знаменитому японському просвітителю."}, {"title": "Старовинні вулички", "text": "Атмосфера епохи Едо та ремісничі крамнички."}, {"title": "Гастрономічна Одавара", "text": "Камабоко (рибні тістечка) та місцеві делікатеси узбережжя Тихого океану."}]}, "en": {"title": "Odawara — City of Invincible Samurai", "summary": "The story of the mighty Hojo clan, an ancient castle, temples, crafts, and culinary traditions on the Pacific coast.", "description": "Odawara is one of the most important historical cities in Kanagawa Prefecture, known for its samurai heritage, the castle of the Hojo clan, and the special atmosphere of old Japan. The main program runs for 6 hours and combines history, culture, crafts, and local cuisine.\r\n\r\nMinaka Odawara — a modern complex styled like a castle town, with a panoramic terrace.\r\n\r\nOdawara Castle — the main highlight: the history of the Hojo clan and its defense against Toyotomi Hideyoshi.\r\n\r\nMuseum of Samurai Armor — a collection of authentic armor and weapons.\r\n\r\nHotoku Ninomiya Shrine — dedicated to Ninomiya Sontoku, the famous educator.\r\n\r\nOld streets — the atmosphere of the Edo era and artisan shops.\r\n\r\nCulinary Odawara — kamaboko (fish cakes) and local delicacies.\r\n\r\nAdditional locations: Tengu Temple (Daiyuzan Saijoji), Suzuhiro Kamaboko Museum, the Matsunaga Residence and a tea ceremony, Odawara Port, Enoura Observatory.", "org_details": "Departure from Tokyo and return after the program ends are possible.\r\nAdditional locations are discussed separately.", "price_details": "Private with transfer from Tokyo: $160/person (group of up to 12 people), entrance tickets to the Castle and the Armor Museum included\r\nWalking tour with meeting at Odawara Station: $140/person", "participants": "up to 12 people", "includes": ["Guide services", "Entrance tickets to Odawara Castle", "Entrance tickets to the Museum of Samurai Armor"], "excludes": ["Additional museums and optional locations"], "stops": [{"title": "Minaka Odawara", "text": "A modern complex styled like a castle town, with a panoramic terrace and a view over the city."}, {"title": "Odawara Castle", "text": "The main highlight: the history of the Hojo clan and its defense against Toyotomi Hideyoshi."}, {"title": "Museum of Samurai Armor", "text": "A collection of authentic samurai armor and weapons."}, {"title": "Hotoku Ninomiya Shrine", "text": "Dedicated to Ninomiya Sontoku — the famous Japanese educator."}, {"title": "Old Streets", "text": "The atmosphere of the Edo era and artisan shops."}, {"title": "Culinary Odawara", "text": "Kamaboko (fish cakes) and local delicacies of the Pacific coast."}]}}'::jsonb WHERE slug = 'odavara';
UPDATE tours SET translations = COALESCE(translations,'{}'::jsonb) || '{"uk": {"title": "Нікко, Оя та Японія епохи самураїв", "summary": "Триденний тур: підземні каменоломні, храми ЮНЕСКО, водоспади та місто-парк епохи Едо.", "description": "День 1 — Підземний світ Оя та бамбуковий ліс\r\n\r\nПідземні каменоломні Оя (Oya History Museum) — підземні зали глибиною до 30 м.\r\n\r\nХрам Оя-дзі — буддійський храм у скелі (1000+ років), статуя Каннон.\r\n\r\nСтатуя Хейва Каннон — 27 м, висічена у скелі.\r\n\r\nБамбуковий ліс Wakayama Farm.\r\n\r\nДень 2 — Священний Нікко та природа гір\r\n\r\nХрамовий комплекс Тосьоґу (ЮНЕСКО) — ворота Йомеймон, «Три мудрі мавпи», «Сплячий кіт».\r\n\r\nХрам Ріннодзі — три священні божества.\r\n\r\nСвятилище Футарасан — 1200+ років.\r\n\r\nМіст Сінкьо.\r\n\r\nАлея Дзідзо Канманґафуті (за бажанням).\r\n\r\nВодоспад Кеґон.\r\n\r\nОзеро Тюдзендзі.\r\n\r\nГірська дорога Ірохадзака.\r\n\r\nДень 3 — Японія епохи Едо\r\n\r\nEdo Wonderland Nikko Edomura — квартали Едо, будинки самураїв, вистави ніндзя, театральні шоу, ремесла, костюми.", "org_details": "Тривалість 3 дні.\r\nТранспортне обслуговування протягом усього туру.\r\nМаршрут адаптується під інтереси гостей.", "price_details": "Для 1–3 осіб: $1950–2250 за тур\r\nДля 4–6 осіб: $2400–2800 за тур\r\nДля 7 осіб: $2800–3150 за тур", "participants": "1–7 осіб", "includes": ["Послуги гіда (3 дні)", "Транспортне обслуговування", "Платні дороги та паркування", "Вхідний квиток до Oya History Museum", "Вхід до храму Оя-дзі", "Вхід до бамбукового лісу Wakayama Farm", "Вхідні квитки до комплексу Тосьоґу", "Вхідні квитки до храму Ріннодзі", "Вхідні квитки до святилища Футарасан", "Вхідний квиток до Edo Wonderland Nikko Edomura"], "excludes": ["Проживання", "Харчування та напої", "Особисті витрати та сувеніри", "Оглядовий ліфт водоспаду Кеґон (за бажанням)", "Додаткові музеї та локації поза програмою"], "stops": [{"title": "Каменоломні Оя", "text": "Підземні зали глибиною до 30 метрів (Oya History Museum)."}, {"title": "Храм Оя-дзі", "text": "Буддійський храм у скелі віком понад 1000 років та статуя Каннон."}, {"title": "Статуя Хейва Каннон", "text": "27-метрова статуя, висічена просто у скелі."}, {"title": "Храмовий комплекс Тосьоґу", "text": "Об''єкт ЮНЕСКО: ворота Йомеймон, «Три мавпи» та «Сплячий кіт»."}, {"title": "Храм Ріннодзі", "text": "Три священні божества та величні зали."}, {"title": "Святилище Футарасан", "text": "Святилище віком понад 1200 років в оточенні гір."}, {"title": "Водоспад Кеґон", "text": "Один із найкрасивіших водоспадів Японії — 97 метрів."}, {"title": "Озеро Тюдзендзі", "text": "Гірське озеро біля підніжжя вулкана Нантай."}, {"title": "Edo Wonderland Nikko Edomura", "text": "Квартали епохи Едо: будинки самураїв, шоу ніндзя, ремесла та костюми."}]}, "en": {"title": "Nikko, Oya, and Japan of the Samurai Era", "summary": "A three-day tour: underground quarries, UNESCO temples, waterfalls, and an Edo-era theme park town.", "description": "Day 1 — The Underground World of Oya and a Bamboo Forest\r\n\r\nThe Oya underground quarries (Oya History Museum) — underground halls up to 30 m deep.\r\n\r\nOya-ji Temple — a Buddhist temple carved into the rock (1,000+ years old), with a Kannon statue.\r\n\r\nHeiwa Kannon statue — 27 m, carved into the cliff.\r\n\r\nWakayama Farm bamboo forest.\r\n\r\nDay 2 — Sacred Nikko and Mountain Nature\r\n\r\nToshogu temple complex (UNESCO) — the Yomeimon Gate, the \"Three Wise Monkeys,\" and the \"Sleeping Cat.\"\r\n\r\nRinnoji Temple — three sacred deities.\r\n\r\nFutarasan Shrine — 1,200+ years old.\r\n\r\nShinkyo Bridge.\r\n\r\nKanmangafuchi Jizo path (optional).\r\n\r\nKegon Waterfall.\r\n\r\nLake Chuzenji.\r\n\r\nIrohazaka mountain road.\r\n\r\nDay 3 — Japan of the Edo Era\r\n\r\nEdo Wonderland Nikko Edomura — Edo quarters, samurai houses, ninja performances, theatrical shows, crafts, and costumes.", "org_details": "Duration: 3 days.\r\nTransportation throughout the entire tour.\r\nThe itinerary is tailored to the guests'' interests.", "price_details": "For 1–3 people: $1,950–2,250 per tour\r\nFor 4–6 people: $2,400–2,800 per tour\r\nFor 7 people: $2,800–3,150 per tour", "participants": "1–7 people", "includes": ["Guide services (3 days)", "Transportation", "Toll roads and parking", "Entrance ticket to the Oya History Museum", "Entry to Oya-ji Temple", "Entry to the Wakayama Farm bamboo forest", "Entrance tickets to the Toshogu complex", "Entrance tickets to Rinnoji Temple", "Entrance tickets to Futarasan Shrine", "Entrance ticket to Edo Wonderland Nikko Edomura"], "excludes": ["Accommodation", "Meals and drinks", "Personal expenses and souvenirs", "The Kegon Waterfall observation elevator (optional)", "Additional museums and locations outside the program"], "stops": [{"title": "Oya Quarries", "text": "Underground halls up to 30 meters deep (Oya History Museum)."}, {"title": "Oya-ji Temple", "text": "A Buddhist temple carved into the rock, over 1,000 years old, with a Kannon statue."}, {"title": "Heiwa Kannon Statue", "text": "A 27-meter statue carved directly into the cliff."}, {"title": "Toshogu Temple Complex", "text": "A UNESCO site: the Yomeimon Gate, the \"Three Monkeys,\" and the \"Sleeping Cat.\""}, {"title": "Rinnoji Temple", "text": "Three sacred deities and majestic halls."}, {"title": "Futarasan Shrine", "text": "A shrine over 1,200 years old, surrounded by mountains."}, {"title": "Kegon Waterfall", "text": "One of Japan''s most beautiful waterfalls — 97 meters high."}, {"title": "Lake Chuzenji", "text": "A mountain lake at the foot of the Nantai volcano."}, {"title": "Edo Wonderland Nikko Edomura", "text": "Edo-era quarters: samurai houses, ninja shows, crafts, and costumes."}]}}'::jsonb WHERE slug = 'nikko';
UPDATE tours SET translations = COALESCE(translations,'{}'::jsonb) || '{"uk": {"title": "Камакура — місто самураїв, храмів і легенд", "summary": "Подорож містом самураїв, історією та легендами колишньої столиці Японії у супроводі гіда.", "description": "Храм Хаседера — позолочена статуя 11-голової богині Каннон, Дзідзо, бамбуковий гай, краєвид на океан.\r\n\r\nВеликий Будда Камакури — бронзова статуя XIII століття.\r\n\r\nСвятилище Дзеніарай Бентен — у природній печері, легенда про фінансову удачу.\r\n\r\nЦуруґаока Хатіманґу — головне святилище, рід Мінамото, перший сьогунат.\r\n\r\nВулиця Коматі-дорі — торгова вулиця, солодощі, сувеніри.\r\n\r\nПляж Юйґахама або оглядовий майданчик.", "org_details": "Тривалість 6–7 годин.\r\nМаршрут може бути адаптований.\r\nМожливі додаткові локації (менш відомі храми, бамбукові гаї, самурайські стежки).", "price_details": "$1000 за екскурсію для групи до 7 осіб незалежно від кількості учасників", "participants": "до 7 осіб", "includes": ["Послуги гіда", "Транспортне обслуговування", "Вхідні квитки за програмою"], "stops": [{"title": "Храм Хаседера", "text": "Позолочена статуя 11-голової богині Каннон, фігури Дзідзо, бамбуковий гай та краєвид на океан."}, {"title": "Великий Будда Камакури", "text": "Бронзова статуя Будди XIII століття просто неба."}, {"title": "Святилище Дзеніарай Бентен", "text": "Святилище у природній печері та легенда про фінансову удачу."}, {"title": "Цуруґаока Хатіманґу", "text": "Головне святилище міста, рід Мінамото та перший сьогунат."}, {"title": "Вулиця Коматі-дорі", "text": "Торгова вуличка зі солодощами та сувенірами."}, {"title": "Пляж Юйґахама", "text": "Узбережжя Камакури та панорама океану."}]}, "en": {"title": "Kamakura — City of Samurai, Temples, and Legends", "summary": "A journey through the city of samurai, the history and legends of Japan''s former capital, accompanied by a guide.", "description": "Hasedera Temple — a gilded statue of the eleven-headed goddess Kannon, Jizo figures, a bamboo grove, and a view of the ocean.\r\n\r\nThe Great Buddha of Kamakura — a 13th-century bronze statue.\r\n\r\nZeniarai Benten Shrine — set in a natural cave, with a legend of financial fortune.\r\n\r\nTsurugaoka Hachimangu — the main shrine, the Minamoto clan, and the first shogunate.\r\n\r\nKomachi-dori Street — a shopping street with sweets and souvenirs.\r\n\r\nYuigahama Beach or a viewpoint.", "org_details": "Duration: 6–7 hours.\r\nThe itinerary can be adapted.\r\nAdditional locations are possible (lesser-known temples, bamboo groves, samurai trails).", "price_details": "$1,000 for the tour for a group of up to 7 people, regardless of the number of participants", "participants": "up to 7 people", "includes": ["Guide services", "Transportation", "Entrance tickets per the program"], "stops": [{"title": "Hasedera Temple", "text": "A gilded statue of the eleven-headed goddess Kannon, Jizo figures, a bamboo grove, and a view of the ocean."}, {"title": "The Great Buddha of Kamakura", "text": "A 13th-century bronze statue of the Buddha out in the open air."}, {"title": "Zeniarai Benten Shrine", "text": "A shrine set in a natural cave and a legend of financial fortune."}, {"title": "Tsurugaoka Hachimangu", "text": "The city''s main shrine, the Minamoto clan, and the first shogunate."}, {"title": "Komachi-dori Street", "text": "A shopping street with sweets and souvenirs."}, {"title": "Yuigahama Beach", "text": "The Kamakura coastline and a panorama of the ocean."}]}}'::jsonb WHERE slug = 'kamakura';
UPDATE tours SET translations = COALESCE(translations,'{}'::jsonb) || '{"uk": {"title": "Камікочі та замок Мацумото — серце Японських Альп", "summary": "Індивідуальна екскурсія з Токіо: національний парк Камікочі в Японських Альпах та «Замок Чорного Ворона» Мацумото за один день.", "description": "Відкрийте для себе дивовижну красу Японських Альп і доторкніться до історії епохи самураїв. Екскурсія об''єднує одну з найбільш мальовничих природних пам''яток Японії — Камікочі — та один із найкрасивіших збережених замків країни.\r\n\r\nМаршрут ідеально підходить для тих, хто хоче за один день побачити одразу дві різні сторони Японії: велич природи національного парку та багату спадщину самурайської епохи.", "org_details": "Камікочі — сезонна пам''ятка, відкрита приблизно з середини квітня до середини листопада (взимку парк закритий через сніг).\r\nВзимку замість Камікочі пропонуємо маршрути регіоном Нагано: парк снігових мавп Дзіґокудані, снігове село Камакура (у період фестивалю), онсен, за бажанням — кілька годин на гірськолижному курорті.\r\nЗа бажанням маршрут можна доповнити: ферма Daio Wasabi, дегустація саке, онсен, винарня регіону Нагано, яблуневі сади (в сезон).", "participants": "Індивідуально", "includes": ["Індивідуальна екскурсія", "Комфортний автомобіль", "Супровід ліцензованого російськомовного гіда", "Гнучкий маршрут з адаптацією програми під ваші побажання"], "stops": [{"title": "Камікочі — перлина Японських Альп", "text": "Один із найкрасивіших національних парків Японії на висоті ~1500 м. Знаменитий міст Каппабасі, кристально чиста річка Адзуса, панорами масиву Хотака та альпійські лісові стежки. (Сезонно: середина квітня — середина листопада.)"}, {"title": "Замок Мацумото", "text": "Один із дванадцяти оригінальних замків Японії кінця XVI століття. «Замок Чорного Ворона» — національне надбання країни; історія самураїв, оборонна архітектура та краєвиди на Альпи."}, {"title": "Історичний центр Мацумото", "text": "Прогулянка атмосферними вулицями Накаматі та Навате: традиційні будинки, ремісничі майстерні, затишні кафе та сувенірні крамнички."}]}, "en": {"title": "Kamikochi and Matsumoto Castle — the Heart of the Japanese Alps", "summary": "A private day tour from Tokyo: Kamikochi National Park in the Japanese Alps and the \"Crow Castle\" of Matsumoto in a single day.", "description": "Discover the astonishing beauty of the Japanese Alps and touch the history of the samurai era. This tour combines one of Japan''s most scenic natural attractions — Kamikochi — with one of the country''s most beautiful surviving castles.\r\n\r\nThe itinerary is ideal for those who want to see two very different sides of Japan in a single day: the grandeur of a national park''s nature and the rich heritage of the samurai era.", "org_details": "Kamikochi is a seasonal attraction, open roughly from mid-April to mid-November (the park is closed in winter due to snow).\r\nIn winter, instead of Kamikochi we offer itineraries around the Nagano region: the Jigokudani snow monkey park, the snow village Kamakura (during the festival period), an onsen, and, if desired, a few hours at a ski resort.\r\nIf you wish, the itinerary can be supplemented with: the Daio Wasabi farm, sake tasting, an onsen, a Nagano-region winery, and apple orchards (in season).", "participants": "Private", "includes": ["Private tour", "Comfortable car", "Accompaniment by a licensed Russian-speaking guide", "A flexible itinerary tailored to your wishes"], "stops": [{"title": "Kamikochi — the Jewel of the Japanese Alps", "text": "One of Japan''s most beautiful national parks, at an altitude of ~1,500 m. The famous Kappabashi Bridge, the crystal-clear Azusa River, panoramas of the Hotaka massif, and alpine forest trails. (Seasonal: mid-April to mid-November.)"}, {"title": "Matsumoto Castle", "text": "One of Japan''s twelve original castles, dating to the late 16th century. The \"Crow Castle\" is a national treasure; samurai history, defensive architecture, and views of the Alps."}, {"title": "Historic Center of Matsumoto", "text": "A stroll along the atmospheric Nakamachi and Nawate streets: traditional houses, artisan workshops, cozy cafes, and souvenir shops."}]}}'::jsonb WHERE slug = 'kamikochi-matsumoto';
UPDATE tours SET translations = COALESCE(translations,'{}'::jsonb) || '{"uk": {"title": "Історичний Токіо з нотками сучасності", "summary": "Храми, архітектура, легенди та найкращі фотолокації японської столиці в товаристві гіда.", "description": "Якщо ви хочете відкрити для себе Токіо й дізнатися його історію від епохи самураїв і сьоґунів до наших днів, варто обрати цю оглядову екскурсію. Мальовничі краєвиди, давні легенди, храми та архітектура епохи Мейдзі — усе це поєднано в захопливій програмі знайомства зі столицею Японії.\r\n\r\nПід час екскурсії ми відвідаємо найвідоміші локації Токіо: Імператорський палац і його символ — витончений міст Нідзюбасі; Токійський вокзал — архітектурну пам''ятку епохи Мейдзі; район Асакуса — один із найстаріших і найатмосферніших куточків міста; історичний діловий район Ніхонбасі — серце старого Токіо; елегантний квартал Ґіндза — центр моди, культури та сучасного життя мегаполіса.\r\n\r\nЦя екскурсія чудово підійде як тим, хто вперше відвідує Токіо, так і мандрівникам, які бажають продовжити знайомство з японською столицею.", "org_details": "Тривалість програми: 4–5 годин активної екскурсії та перерва на обід.\r\nДля груп від 8 до 20 осіб можливе проведення екскурсії громадським транспортом.\r\nУ вартість входять послуги гіда та автомобільний супровід.\r\nМаршрут може коригуватися залежно від погодних умов, дорожньої ситуації та побажань гостей.", "price_details": "Громадським транспортом: $480\r\nЗ трансфером (автомобіль): $680", "participants": "до 6 осіб", "includes": ["Послуги гіда", "Автомобільний супровід"], "stops": [{"title": "Імператорський палац і міст Нідзюбасі", "text": "Починаємо в самому серці Токіо — біля Імператорського палацу, резиденції імператорської родини. Помилуємося витонченим мостом Нідзюбасі й поговоримо про історію імператорського дому."}, {"title": "Токійський вокзал", "text": "Архітектурна пам''ятка епохи Мейдзі: червоноцегляний фасад початку XX століття, дбайливо відновлений у первісному вигляді."}, {"title": "Район Асакуса", "text": "Один із найстаріших і найатмосферніших куточків міста: храм Сенсо-дзі, торгова вуличка Накамісе та дух старого Едо."}, {"title": "Ніхонбасі", "text": "Історичний діловий район — серце старого Токіо й точка відліку всіх доріг Японії."}, {"title": "Квартал Ґіндза", "text": "Елегантний квартал — центр моди, культури та сучасного життя мегаполіса."}]}, "en": {"title": "Historic Tokyo with a Touch of the Modern", "summary": "Temples, architecture, legends, and the best photo spots of the Japanese capital in the company of a guide.", "description": "If you want to discover Tokyo and learn its history — from the era of samurai and shoguns to the present day — this sightseeing tour is for you. Scenic landscapes, ancient legends, temples, and Meiji-era architecture are all woven into an engaging program to get to know Japan''s capital.\r\n\r\nDuring the tour we will visit Tokyo''s most famous landmarks: the Imperial Palace and its symbol, the graceful Nijubashi Bridge; Tokyo Station — an architectural monument of the Meiji era; the Asakusa district — one of the oldest and most atmospheric corners of the city; the historic business district of Nihonbashi — the heart of old Tokyo; and the elegant Ginza quarter — a center of fashion, culture, and modern metropolitan life.\r\n\r\nThis tour is perfect both for first-time visitors to Tokyo and for travelers wishing to continue their acquaintance with the Japanese capital.", "org_details": "Program duration: 4–5 hours of active touring plus a lunch break.\r\nFor groups of 8 to 20 people, the tour can be conducted by public transport.\r\nThe price includes the services of a guide and car escort.\r\nThe route may be adjusted depending on weather conditions, traffic, and guests'' wishes.", "price_details": "By public transport: $480\r\nWith transfer (car): $680", "participants": "up to 6 people", "includes": ["Guide services", "Car escort"], "stops": [{"title": "Imperial Palace and Nijubashi Bridge", "text": "We begin in the very heart of Tokyo — at the Imperial Palace, the residence of the imperial family. We will admire the graceful Nijubashi Bridge and talk about the history of the imperial house."}, {"title": "Tokyo Station", "text": "An architectural monument of the Meiji era: an early-20th-century red-brick facade, carefully restored to its original appearance."}, {"title": "Asakusa District", "text": "One of the oldest and most atmospheric corners of the city: Senso-ji Temple, the Nakamise shopping street, and the spirit of old Edo."}, {"title": "Nihonbashi", "text": "A historic business district — the heart of old Tokyo and the starting point of all of Japan''s roads."}, {"title": "Ginza Quarter", "text": "An elegant quarter — a center of fashion, culture, and modern metropolitan life."}]}}'::jsonb WHERE slug = 'istoricheskiy-tokio';
UPDATE tours SET translations = COALESCE(translations,'{}'::jsonb) || '{"uk": {"title": "Токіо після заходу сонця: неон, панорами та ритм мегаполіса", "summary": "Вечірній Токіо — неонові вогні, хмарочоси, знаменитий перехрестя Сібуя та атмосферні провулки.", "description": "Маршрут розрахований на другу половину дня (приблизно з 15:00 до 21:00) і охоплює найяскравіші вечірні локації Токіо.\r\n\r\nОдайба (15:00–16:00) — Райдужний міст, Статуя Свободи, узбережжя Токійської затоки, сучасна архітектура.\r\n\r\nҐіндза (16:00–17:00) — сучасна архітектура, флагманські магазини, історичні універмаги, вишукана атмосфера.\r\n\r\nХарадзюку (17:00–18:00) — молодіжна мода, вулиця Такесіта-дорі.\r\n\r\nСібуя (18:00–19:00) — Shibuya Crossing, пам''ятник Хатіко, Shibuya Sky (за бажанням).\r\n\r\nСіндзюку (19:00–20:00) — хмарочоси, один із найбільших вокзалів світу.\r\n\r\nКабукі-тьо та Omoide Yokocho (20:00–21:00) — неонові вогні, 3D-кіт, вузькі провулки з ресторанчиками.", "price_details": "Громадським транспортом (робота гіда): $550\r\nНа трансфері (замовленому авто): ціна обговорюється окремо", "includes": ["Послуги гіда"], "stops": [{"title": "Одайба", "text": "Райдужний міст, Статуя Свободи, узбережжя Токійської затоки та сучасна архітектура на заході сонця."}, {"title": "Ґіндза", "text": "Сучасна архітектура, флагманські магазини та історичні універмаги — вишукана вечірня атмосфера."}, {"title": "Харадзюку", "text": "Молодіжна мода та знаменита вулиця Такесіта-дорі."}, {"title": "Сібуя", "text": "Легендарне перехрестя Shibuya Crossing, пам''ятник Хатіко та оглядовий майданчик Shibuya Sky (за бажанням)."}, {"title": "Сіндзюку", "text": "Хмарочоси та один із найбільших вокзалів світу у вогнях вечірнього міста."}, {"title": "Кабукі-тьо та Omoide Yokocho", "text": "Неонові вогні, знаменитий 3D-кіт та вузькі провулки з крихітними ресторанчиками."}]}, "en": {"title": "Tokyo After Sunset: Neon, Panoramas, and the Rhythm of the Metropolis", "summary": "Evening Tokyo — neon lights, skyscrapers, the famous Shibuya Crossing, and atmospheric back alleys.", "description": "The route is designed for the afternoon and evening (roughly 3:00 p.m. to 9:00 p.m.) and covers Tokyo''s most vibrant nighttime locations.\r\n\r\nOdaiba (3:00–4:00 p.m.) — Rainbow Bridge, the Statue of Liberty, the Tokyo Bay waterfront, and modern architecture.\r\n\r\nGinza (4:00–5:00 p.m.) — modern architecture, flagship stores, historic department stores, and a refined atmosphere.\r\n\r\nHarajuku (5:00–6:00 p.m.) — youth fashion and Takeshita Street.\r\n\r\nShibuya (6:00–7:00 p.m.) — Shibuya Crossing, the Hachiko statue, Shibuya Sky (optional).\r\n\r\nShinjuku (7:00–8:00 p.m.) — skyscrapers and one of the largest train stations in the world.\r\n\r\nKabukicho and Omoide Yokocho (8:00–9:00 p.m.) — neon lights, the 3D cat, and narrow alleys lined with tiny eateries.", "price_details": "By public transport (guide service): $550\r\nWith transfer (chartered car): price discussed separately", "includes": ["Guide services"], "stops": [{"title": "Odaiba", "text": "Rainbow Bridge, the Statue of Liberty, the Tokyo Bay waterfront, and modern architecture at sunset."}, {"title": "Ginza", "text": "Modern architecture, flagship stores, and historic department stores — a refined evening atmosphere."}, {"title": "Harajuku", "text": "Youth fashion and the famous Takeshita Street."}, {"title": "Shibuya", "text": "The legendary Shibuya Crossing, the Hachiko statue, and the Shibuya Sky observation deck (optional)."}, {"title": "Shinjuku", "text": "Skyscrapers and one of the largest train stations in the world amid the lights of the evening city."}, {"title": "Kabukicho and Omoide Yokocho", "text": "Neon lights, the famous 3D cat, and narrow alleys lined with tiny eateries."}]}}'::jsonb WHERE slug = 'tokio-posle-zakata';
UPDATE tours SET translations = COALESCE(translations,'{}'::jsonb) || '{"uk": {"title": "Фудзі — священна гора Японії та смак справжнього зеленого чаю", "summary": "Індивідуальна екскурсія з порту Сімідзу: чайні плантації з видом на Фудзі, водоспад Сіраіто, дегустація саке (за бажанням) та головне святилище гори Фудзі.", "description": "На вас чекає подорож мальовничими дорогами префектури Сідзуока — регіону, де вирощують найкращий зелений чай Японії, відкриваються неймовірні панорами на Фудзі та зберігаються давні традиції.\r\n\r\nЧайні плантації Сідзуоки з видом на Фудзі. Сідзуока виробляє близько 40% усього японського зеленого чаю. Ми відвідаємо мальовничі чайні плантації, де можна побачити нескінченні смарагдові поля на тлі священної гори Фудзі, дізнатися про процес вирощування та виробництва японського чаю, а також зрозуміти, чому японці приділяють так багато уваги кожній чашці цього напою. Під час екскурсії ви дізнаєтеся: як збирають чайний лист; чим відрізняються сенча, ґьокуро та матча; як правильно заварювати й пити зелений чай по-японськи; чому температура води така важлива для смаку.\r\n\r\nВодоспад Сіраіто — один із найкрасивіших водоспадів Японії та об''єкт Всесвітньої спадщини ЮНЕСКО. Сотні кристально чистих струменів води спадають зі скелі, створюючи враження білосніжної шовкової завіси.\r\n\r\nСакеварня та дегустація (за бажанням). Відвідування традиційної японської сакеварні, де можна познайомитися з процесом виробництва саке та продегустувати різні сорти напою (бронювання обов''язкове). Для тих, хто не вживає алкоголь, цікава сама історія виробництва та традиції японського рисового виноробства.\r\n\r\nСвятилище Fujisan Hongū Sengen Taisha — головне святилище гори Фудзі та духовний центр усіх паломників, які століттями здійснювали сходження на священну вершину. Тут ми поговоримо про легенди Фудзі, синтоїзм та особливе місце гори в японській культурі.\r\n\r\nАльтернативна програма на випадок дощу: замість частини відкритих локацій ми відвідаємо Mount Fuji World Heritage Centre — сучасний музей, присвячений історії, природі та культурному значенню гори Фудзі. Унікальна архітектура будівлі та інтерактивні експозиції дозволяють побачити Фудзі навіть тоді, коли вона прихована за хмарами.", "org_details": "Основні локації: чайні плантації Сідзуоки · водоспад Сіраіто · сакеварня (за бажанням, бронювання обов''язкове) · святилище Fujisan Hongū Sengen Taisha. Альтернатива в дощ: Mount Fuji World Heritage Centre.", "price_details": "$1300 за екскурсію (1–6 гостей).\r\nУ ціну входять усі вхідні квитки за маршрутом.", "participants": "1–6 гостей", "includes": ["Зустріч і повернення в порт Сімідзу", "Комфортний автомобіль", "Послуги ліцензованого гіда", "Індивідуальний маршрут без великих туристичних груп", "Усі вхідні квитки за маршрутом"], "excludes": ["Дегустація саке (за бажанням, бронювання обов''язкове)"], "stops": [{"title": "Чайні плантації Сідзуоки", "text": "Смарагдові поля чаю на тлі Фудзі; Сідзуока дає ~40% зеленого чаю Японії."}, {"title": "Водоспад Сіраіто", "text": "Об''єкт ЮНЕСКО: сотні струменів води, наче білосніжна шовкова завіса."}, {"title": "Сакеварня та дегустація", "text": "Традиційна японська сакеварня та історія рисового виноробства (за бажанням)."}, {"title": "Fujisan Hongū Sengen Taisha", "text": "Головне святилище гори Фудзі та духовний центр паломників."}]}, "en": {"title": "Mt. Fuji — Japan''s Sacred Mountain and the Taste of True Green Tea", "summary": "A private tour from the port of Shimizu: tea plantations with views of Mt. Fuji, Shiraito Falls, a sake tasting (optional), and the main shrine of Mt. Fuji.", "description": "A journey awaits you along the scenic roads of Shizuoka Prefecture — a region that grows Japan''s finest green tea, offers incredible panoramas of Mt. Fuji, and preserves ancient traditions.\r\n\r\nThe tea plantations of Shizuoka with views of Mt. Fuji. Shizuoka produces about 40% of all Japanese green tea. We will visit picturesque tea plantations where you can see endless emerald fields against the backdrop of sacred Mt. Fuji, learn about the cultivation and production of Japanese tea, and understand why the Japanese devote so much attention to every cup of this beverage. During the tour you will learn: how tea leaves are harvested; how sencha, gyokuro, and matcha differ; how to properly brew and drink green tea the Japanese way; and why water temperature is so important to the flavor.\r\n\r\nShiraito Falls — one of the most beautiful waterfalls in Japan and a UNESCO World Heritage Site. Hundreds of crystal-clear streams of water cascade down the cliff, creating the impression of a snow-white silk veil.\r\n\r\nSake brewery and tasting (optional). A visit to a traditional Japanese sake brewery, where you can learn about the sake-making process and taste different varieties of the beverage (reservation required). For those who do not drink alcohol, the history of production and the traditions of Japanese rice winemaking are interesting in themselves.\r\n\r\nFujisan Hongu Sengen Taisha Shrine — the main shrine of Mt. Fuji and the spiritual center of all the pilgrims who for centuries made the ascent to the sacred summit. Here we will talk about the legends of Mt. Fuji, Shinto, and the mountain''s special place in Japanese culture.\r\n\r\nAlternative program in case of rain: instead of some of the outdoor locations, we will visit the Mount Fuji World Heritage Centre — a modern museum dedicated to the history, nature, and cultural significance of Mt. Fuji. The building''s unique architecture and interactive exhibits let you see Fuji even when it is hidden behind the clouds.", "org_details": "Main locations: the tea plantations of Shizuoka · Shiraito Falls · sake brewery (optional, reservation required) · Fujisan Hongu Sengen Taisha Shrine. Rainy-day alternative: Mount Fuji World Heritage Centre.", "price_details": "$1300 per tour (1–6 guests).\r\nThe price includes all admission tickets along the route.", "participants": "1–6 guests", "includes": ["Pickup and return at the port of Shimizu", "Comfortable car", "Services of a licensed guide", "A private itinerary without large tourist groups", "All admission tickets along the route"], "excludes": ["Sake tasting (optional, reservation required)"], "stops": [{"title": "The Tea Plantations of Shizuoka", "text": "Emerald tea fields against the backdrop of Mt. Fuji; Shizuoka produces ~40% of Japan''s green tea."}, {"title": "Shiraito Falls", "text": "A UNESCO site: hundreds of streams of water like a snow-white silk veil."}, {"title": "Sake Brewery and Tasting", "text": "A traditional Japanese sake brewery and the history of rice winemaking (optional)."}, {"title": "Fujisan Hongu Sengen Taisha", "text": "The main shrine of Mt. Fuji and the spiritual center for pilgrims."}]}}'::jsonb WHERE slug = 'fuji-chay-svyatynya';
UPDATE tours SET translations = COALESCE(translations,'{}'::jsonb) || '{"uk": {"title": "Ідзу — де вулкани зустрічаються з океаном", "summary": "Подорож до Японії, якої не очікуєш: кратери давніх вулканів, старовинні онсени, океанські скелі та панорами Фудзі.", "description": "День 1 — Панорами Фудзі, вулкани та старовинні онсени\r\n\r\nIzu Panorama Park і Ao Terrace — панорамна канатна дорога, вид на затоку Суруга та Фудзі.\r\n\r\nСюдзендзі Онсен — старовинне онсен-містечко, бамбуковий гай, храм із тисячолітньою історією.\r\n\r\nГора Омуро — ідеальний вулканічний конус, прогулянка по краю кратера.\r\n\r\nУзбережжя Дзьоґасакі — лавові скелі, підвісний міст над океаном.\r\n\r\nДодатково: онсен із видом на океан, Izu Shaboten Zoo, дегустація васабі.\r\n\r\nДень 2 — Золото самураїв, водоспади та край Тихого океану\r\n\r\nВодоспади Кавадзу — сім водоспадів серед лісів і скель.\r\n\r\nОнсен-гейзер та онсен-яйця.\r\n\r\nМис Іродзакі — найпівденніша точка півострова, маяк.\r\n\r\nЗолота копальня Тої — найбільший золотий зливок Японії (250 кг).\r\n\r\nДодатково: Доґасіма та морські печери, круїз, Дарумаяма, океанський онсен.\r\n\r\nДля кого: пари, родини з дітьми, фотографи, любителі природи, мандрівники за межами стандартних маршрутів.", "org_details": "Можливий виїзд із Токіо, Одавари, Хаконе та інших міст регіону Канто.", "price_details": "Одноденна поїздка з Токіо: $1300 за групу 1–6 осіб.\r\nДводенна поїздка: $2250 за групу 1–6 осіб.\r\nГрупи від 7 осіб — обговорюються індивідуально.", "participants": "1–6 осіб", "includes": ["Послуги гіда", "Транспортне обслуговування"], "excludes": ["Проживання (за дводенної)", "Харчування", "Особисті витрати"], "stops": [{"title": "Izu Panorama Park і Ao Terrace", "text": "Панорамна канатна дорога, вид на затоку Суруга та гору Фудзі."}, {"title": "Сюдзендзі Онсен", "text": "Старовинне онсен-містечко, бамбуковий гай і храм із тисячолітньою історією."}, {"title": "Гора Омуро", "text": "Ідеальний вулканічний конус і прогулянка по краю кратера."}, {"title": "Узбережжя Дзьоґасакі", "text": "Лавові скелі та підвісний міст над океаном."}, {"title": "Водоспади Кавадзу", "text": "Сім водоспадів серед лісів і скель."}, {"title": "Онсен-гейзер та онсен-яйця", "text": "Гарячі джерела, гейзер і яйця, зварені у природній воді."}, {"title": "Мис Іродзакі", "text": "Найпівденніша точка півострова та старовинний маяк."}, {"title": "Золота копальня Тої", "text": "Найбільший золотий зливок Японії — 250 кг."}]}, "en": {"title": "Izu — Where Volcanoes Meet the Ocean", "summary": "A journey to a Japan you wouldn''t expect: craters of ancient volcanoes, historic onsen towns, ocean cliffs and views of Mt. Fuji.", "description": "Day 1 — Views of Mt. Fuji, Volcanoes and Historic Onsen\r\n\r\nIzu Panorama Park and Ao Terrace — a panoramic ropeway with views of Suruga Bay and Mt. Fuji.\r\n\r\nShuzenji Onsen — a historic onsen town, a bamboo grove and a temple with a thousand-year history.\r\n\r\nMt. Omuro — a perfect volcanic cone with a walk around the crater rim.\r\n\r\nJogasaki Coast — lava cliffs and a suspension bridge over the ocean.\r\n\r\nOptional: an onsen with ocean views, Izu Shaboten Zoo, a wasabi tasting.\r\n\r\nDay 2 — Samurai Gold, Waterfalls and the Edge of the Pacific\r\n\r\nKawazu Waterfalls — seven waterfalls amid forests and rocks.\r\n\r\nAn onsen geyser and onsen eggs.\r\n\r\nCape Irozaki — the southernmost point of the peninsula, with a lighthouse.\r\n\r\nToi Gold Mine — Japan''s largest gold ingot (250 kg).\r\n\r\nOptional: Dogashima and the sea caves, a cruise, Mt. Daruma, an oceanside onsen.\r\n\r\nWho it''s for: couples, families with children, photographers, nature lovers, and travelers looking beyond the standard routes.", "org_details": "Departures available from Tokyo, Odawara, Hakone and other cities in the Kanto region.", "price_details": "One-day trip from Tokyo: $1300 per group of 1–6 people.\r\nTwo-day trip: $2250 per group of 1–6 people.\r\nGroups of 7 or more — arranged individually.", "participants": "1–6 people", "includes": ["Guide services", "Transportation"], "excludes": ["Accommodation (for the two-day tour)", "Meals", "Personal expenses"], "stops": [{"title": "Izu Panorama Park and Ao Terrace", "text": "A panoramic ropeway with views of Suruga Bay and Mt. Fuji."}, {"title": "Shuzenji Onsen", "text": "A historic onsen town, a bamboo grove and a temple with a thousand-year history."}, {"title": "Mt. Omuro", "text": "A perfect volcanic cone with a walk around the crater rim."}, {"title": "Jogasaki Coast", "text": "Lava cliffs and a suspension bridge over the ocean."}, {"title": "Kawazu Waterfalls", "text": "Seven waterfalls amid forests and rocks."}, {"title": "Onsen geyser and onsen eggs", "text": "Hot springs, a geyser and eggs boiled in the natural water."}, {"title": "Cape Irozaki", "text": "The southernmost point of the peninsula and a historic lighthouse."}, {"title": "Toi Gold Mine", "text": "Japan''s largest gold ingot — 250 kg."}]}}'::jsonb WHERE slug = 'idzu';
UPDATE tours SET translations = COALESCE(translations,'{}'::jsonb) || '{"uk": {"title": "Сімідзу: Фудзі, святині сьоґунів та морське узбережжя", "summary": "Індивідуальна екскурсія для гостей круїзних лайнерів: оглядовий майданчик Ніхондайра, святилище Кунодзан Тосьоґу, поселення періоду Яйої та соснова алея Міхо-но-Мацубара.", "description": "Порт Сімідзу вважається одним із найкрасивіших портів Японії. Саме звідси відкриваються знамениті види на гору Фудзі, а поєднання моря, гір і багатовікової історії робить цей регіон справжньою перлиною префектури Сідзуока. Запрошую вас у подорож місцями, де творилася історія Японії, а панорами настільки гарні, що назавжди залишаються в памʼяті.\r\n\r\nНаша подорож розпочнеться на оглядовому майданчику Ніхондайра. У ясну погоду звідси відкривається один із найкращих видів на гору Фудзі, затоку Суруга та зелені пагорби Сідзуоки.\r\n\r\nДалі на нас чекає мальовнича поїздка канатною дорогою Nihondaira Ropeway до храмового комплексу Кунодзан Тосьоґу — мавзолею великого сьоґуна Токуґави Іеясу. Розкішне оздоблення храму, давні кедри та атмосфера святого місця дозволяють відчути велич епохи сьоґунів.\r\n\r\nПісля знайомства з історією ми перенесемося ще далі в минуле, відвідавши археологічний комплекс Торо. Тут просто неба відтворено поселення періоду Яйої, яке дозволяє побачити, як жили японці понад дві тисячі років тому.\r\n\r\nЗавершенням маршруту стане легендарне узбережжя Міхо-но-Мацубара — знаменита соснова алея, внесена до списку Всесвітньої спадщини ЮНЕСКО як частина культурного ландшафту гори Фудзі. Саме тут розташовані одні з найвідоміших листівкових видів Японії.\r\n\r\nЦя екскурсія ідеально підходить для тих, хто хоче за кілька годин побачити головні символи регіону, насолодитися природою, історією та неповторною атмосферою справжньої Японії.", "org_details": "Основні локації: Ніхондайра · канатна дорога Nihondaira Ropeway · храм Кунодзан Тосьоґу · археологічний комплекс Торо · узбережжя Міхо-но-Мацубара.", "participants": "Індивідуально (для гостей круїзу)", "includes": ["Зустріч і повернення в порт Сімідзу", "Комфортний автомобіль", "Послуги ліцензованого гіда", "Індивідуальний маршрут без великих туристичних груп"], "stops": [{"title": "Ніхондайра", "text": "Оглядовий майданчик з одним із найкращих видів на Фудзі, затоку Суруга та пагорби Сідзуоки."}, {"title": "Канатна дорога та Кунодзан Тосьоґу", "text": "Поїздка канатною дорогою до мавзолею сьоґуна Токуґави Іеясу."}, {"title": "Археологічний комплекс Торо", "text": "Відтворене поселення періоду Яйої просто неба."}, {"title": "Узбережжя Міхо-но-Мацубара", "text": "Соснова алея ЮНЕСКО та знамениті листівкові види на Фудзі."}]}, "en": {"title": "Shimizu: Mt. Fuji, Shogun Shrines and the Sea Coast", "summary": "A private tour for cruise ship guests: the Nihondaira observation deck, the Kunozan Toshogu shrine, a Yayoi-period settlement and the Miho-no-Matsubara pine grove.", "description": "The port of Shimizu is considered one of the most beautiful ports in Japan. It is from here that the famous views of Mt. Fuji open up, and the blend of sea, mountains and centuries of history makes this region a true gem of Shizuoka Prefecture. I invite you on a journey through places where the history of Japan was made, with panoramas so beautiful they stay in your memory forever.\r\n\r\nOur journey begins at the Nihondaira observation deck. On a clear day it offers one of the finest views of Mt. Fuji, Suruga Bay and the green hills of Shizuoka.\r\n\r\nNext comes a scenic ride on the Nihondaira Ropeway to the Kunozan Toshogu temple complex — the mausoleum of the great shogun Tokugawa Ieyasu. The temple''s lavish decoration, ancient cedars and the atmosphere of a sacred site let you feel the grandeur of the shogun era.\r\n\r\nAfter exploring this history, we travel even further into the past, visiting the Toro archaeological site. Here, in the open air, a Yayoi-period settlement has been recreated, showing how the Japanese lived more than two thousand years ago.\r\n\r\nThe route concludes at the legendary Miho-no-Matsubara coast — a famous pine grove inscribed on the UNESCO World Heritage list as part of the cultural landscape of Mt. Fuji. This is the setting for some of the most famous postcard views of Japan.\r\n\r\nThis tour is ideal for those who want to see the region''s main symbols in just a few hours and enjoy the nature, history and unique atmosphere of the real Japan.", "org_details": "Main locations: Nihondaira · Nihondaira Ropeway · Kunozan Toshogu shrine · Toro archaeological site · Miho-no-Matsubara coast.", "participants": "Private (for cruise guests)", "includes": ["Pickup and return at the port of Shimizu", "Comfortable car", "Services of a licensed guide", "A private itinerary without large tourist groups"], "stops": [{"title": "Nihondaira", "text": "An observation deck with one of the finest views of Mt. Fuji, Suruga Bay and the hills of Shizuoka."}, {"title": "The ropeway and Kunozan Toshogu", "text": "A ropeway ride to the mausoleum of the shogun Tokugawa Ieyasu."}, {"title": "Toro archaeological site", "text": "A recreated Yayoi-period settlement in the open air."}, {"title": "Miho-no-Matsubara coast", "text": "A UNESCO pine grove and the famous postcard views of Mt. Fuji."}]}}'::jsonb WHERE slug = 'shimizu-fuji-svyatyni';
UPDATE tours SET translations = COALESCE(translations,'{}'::jsonb) || '{"uk": {"title": "Самурайський Мацумото — історія, гастрономія та Японські Альпи", "summary": "Індивідуальна екскурсія з Токіо: давнє святилище Сува Тайся, старовинна місо-броварня, «Замок Чорного Ворона» Мацумото та ферма справжнього васабі.", "description": "Відкрийте для себе один із найкрасивіших регіонів центральної Японії — місце, де давня історія самураїв, величні гори та багатовікові гастрономічні традиції створюють зовсім особливу атмосферу.\r\n\r\nЦя екскурсія — не просто поїздка до знаменитого замку Мацумото. Це справжня подорож регіоном Сінсю, де ви познайомитеся з давніми святинями, скуштуєте страви традиційної японської кухні, дізнаєтеся секрети виробництва знаменитого місо та побачите одну з найбільших ферм справжнього васабі.\r\n\r\nЕкскурсія створена для тих, хто хоче побачити справжню Японію — не лише її знамениті памʼятки, а й атмосферу старовинних міст, традиційну кухню, мальовничу природу та багату культурну спадщину регіону Сінсю.", "org_details": "Індивідуальний автомобіль, без поспіху та великих туристичних груп.\r\nЗа бажанням маршрут можна доповнити: ферма Daio Wasabi, святилище Hotaka, родинна винарня регіону Нагано, яблуневі сади (у сезон), дегустація місцевого саке.", "participants": "Індивідуально", "includes": ["Комфортний автомобіль", "Послуги ліцензованого російськомовного гіда", "Індивідуальний маршрут без великих туристичних груп", "Гнучка програма під ваші побажання"], "stops": [{"title": "Сува Тайся — давнє синтоїстське святилище", "text": "Подорож починається з легендарного комплексу Сува Тайся, історія якого налічує понад 1200 років. Святилище присвячене божествам природи, гір та озер; раз на шість років тут відбувається знаменитий фестиваль Онбасіра."}, {"title": "Озеро Сува", "text": "Невелика зупинка біля мальовничого озера в оточенні гір Японських Альп — чудове місце для відпочинку та гарних фотографій."}, {"title": "Ishii Miso — старовинна місо-броварня", "text": "Родинна броварня, заснована 1868 року. Уже понад 150 років тут роблять трирічне місо природного бродіння у величезних кедрових бочках. Невелика екскурсія та дегустація фірмових страв Сінсю."}, {"title": "Замок Мацумото", "text": "Один із дванадцяти оригінальних замків Японії, що збереглися з епохи самураїв. Збудований понад 400 років тому, він відомий як «Замок Чорного Ворона» завдяки чорному фасаду. Давні інтерʼєри, оборонні споруди та види на Японські Альпи."}, {"title": "Daio Wasabi Farm (за бажанням)", "text": "Одна з найбільших васабі-ферм Японії. Кристально чиста гірська вода, мальовничі канали, незвичні страви з васабі та знамените морозиво."}]}, "en": {"title": "Samurai Matsumoto — History, Cuisine and the Japanese Alps", "summary": "A private tour from Tokyo: the ancient Suwa Taisha shrine, a historic miso brewery, Matsumoto''s \"Crow Castle,\" and a real wasabi farm.", "description": "Discover one of the most beautiful regions of central Japan — a place where the ancient history of the samurai, majestic mountains and centuries-old culinary traditions create a truly special atmosphere.\r\n\r\nThis tour is more than just a trip to the famous Matsumoto Castle. It is a real journey through the Shinshu region, where you will encounter ancient shrines, taste dishes of traditional Japanese cuisine, learn the secrets of producing famous miso, and see one of the largest farms of genuine wasabi.\r\n\r\nThe tour is designed for those who want to see the real Japan — not only its famous sights, but also the atmosphere of historic towns, traditional cuisine, picturesque nature and the rich cultural heritage of the Shinshu region.", "org_details": "A private car, without rushing or large tourist groups.\r\nIf you wish, the route can be supplemented with: the Daio Wasabi farm, the Hotaka shrine, a family winery in the Nagano region, apple orchards (in season), and a tasting of local sake.", "participants": "Private", "includes": ["Comfortable car", "Services of a licensed Russian-speaking guide", "A private itinerary without large tourist groups", "A flexible program tailored to your wishes"], "stops": [{"title": "Suwa Taisha — an ancient Shinto shrine", "text": "The journey begins at the legendary Suwa Taisha complex, whose history spans more than 1,200 years. The shrine is dedicated to the deities of nature, mountains and lakes; every six years it hosts the famous Onbashira festival."}, {"title": "Lake Suwa", "text": "A short stop by a picturesque lake surrounded by the Japanese Alps — a wonderful spot to rest and take beautiful photographs."}, {"title": "Ishii Miso — a historic miso brewery", "text": "A family brewery founded in 1868. For more than 150 years it has produced three-year naturally fermented miso in huge cedar barrels. A short tour and a tasting of signature Shinshu dishes."}, {"title": "Matsumoto Castle", "text": "One of Japan''s twelve original castles surviving from the samurai era. Built more than 400 years ago, it is known as the \"Crow Castle\" for its black facade. Ancient interiors, defensive structures and views of the Japanese Alps."}, {"title": "Daio Wasabi Farm (optional)", "text": "One of Japan''s largest wasabi farms. Crystal-clear mountain water, scenic canals, unusual wasabi dishes and the famous ice cream."}]}}'::jsonb WHERE slug = 'matsumoto-samurai';

UPDATE special_routes SET translations = COALESCE(translations,'{}'::jsonb) || '{"uk": {"title": "Сакура навесні", "description": "Маршрути в сезон цвітіння сакури (кінець березня — квітень): найкращі парки, алеї та краєвиди ханамі."}, "en": {"title": "Sakura in Spring", "description": "Routes during the cherry-blossom season (late March to April): the finest parks, blossom-lined avenues and hanami views."}}'::jsonb WHERE slug = 'sakura-vesnoy';
