UPDATE special_routes SET translations = COALESCE(translations,'{}'::jsonb) || '{"uk": {"title": "Фототури", "description": "Маршрути найфотогенічнішими локаціями Японії — для гарних кадрів і неквапливої зйомки."}, "en": {"title": "Photo Tours", "description": "Routes through Japan''s most photogenic spots — for beautiful shots and unhurried photography."}}'::jsonb WHERE slug = 'fototury';
UPDATE special_routes SET translations = COALESCE(translations,'{}'::jsonb) || '{"uk": {"title": "Японські Альпи", "description": "Гірські напрямки центральної Японії: Камікочі, Нагано, самурайські замки та альпійські панорами."}, "en": {"title": "Japanese Alps", "description": "Mountain destinations in central Japan: Kamikochi, Nagano, samurai castles and alpine panoramas."}}'::jsonb WHERE slug = 'yaponskie-alpy';
UPDATE special_routes SET translations = COALESCE(translations,'{}'::jsonb) || '{"uk": {"title": "Традиційні села", "description": "Старовинні села та поштові містечка: дерев''яні будинки, ремесла й атмосфера старої Японії."}, "en": {"title": "Traditional Villages", "description": "Ancient villages and old post towns: wooden houses, crafts and the atmosphere of old Japan."}}'::jsonb WHERE slug = 'tradicionnye-syola';
